import React, { useState } from "react";

const LoginPage = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [step, setStep] = useState(1);
  const [otp, setOtp] = useState("");
  const [generatedOtp, setGeneratedOtp] = useState("");

  // Instead of useState, define them as constants
  const isTwoStepEnabled = true; 
  const isMultiStepEnabled = true; 

  // Function to generate a random 6-digit OTP
  const generateOtp = () => Math.floor(100000 + Math.random() * 900000).toString();

  const handleLogin = (e) => {
    e.preventDefault();
    console.log("Login successful, checking verification settings...");

    if (isTwoStepEnabled) {
      const newOtp = generateOtp();
      setGeneratedOtp(newOtp);
      alert(`Two-Step OTP: ${newOtp}`);
      setStep(2);
    } else if (isMultiStepEnabled) {
      const newOtp = generateOtp();
      setGeneratedOtp(newOtp);
      alert(`Multi-Step OTP: ${newOtp}`);
      setStep(3);
    } else {
      alert("Login Successful! 🎉");
    }
  };

  const handleTwoStepVerification = (e) => {
    e.preventDefault();
    if (otp === generatedOtp) {
      if (isMultiStepEnabled) {
        const newOtp = generateOtp();
        setGeneratedOtp(newOtp);
        setOtp(""); 
        alert(`Multi-Step OTP: ${newOtp}`);
        setStep(3);
      } else {
        alert("Login Successful! 🎉");
      }
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  const handleMultiStepVerification = (e) => {
    e.preventDefault();
    if (otp === generatedOtp) {
      alert("Login Successful! 🎉");
    } else {
      alert("Invalid OTP. Please try again.");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-100">
      <div className="bg-white p-6 rounded-lg shadow-lg w-96">
        <h2 className="text-2xl font-bold text-center mb-4">Login</h2>

        {step === 1 && (
          <form onSubmit={handleLogin}>
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Email</label>
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter your email"
              />
            </div>

            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Password</label>
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter your password"
              />
            </div>

            <button
              type="submit"
              className="bg-blue-600 text-white w-full py-2 rounded-lg hover:bg-blue-700"
            >
              Login
            </button>
          </form>
        )}

        {step === 2 && (
          <form onSubmit={handleTwoStepVerification}>
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Enter Two-Step OTP</label>
              <input
                type="text"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter OTP"
              />
            </div>

            <button
              type="submit"
              className="bg-blue-600 text-white w-full py-2 rounded-lg hover:bg-blue-700"
            >
              Verify OTP
            </button>
          </form>
        )}

        {step === 3 && (
          <form onSubmit={handleMultiStepVerification}>
            <div className="mb-4">
              <label className="block text-gray-700 font-semibold">Enter Multi-Step OTP</label>
              <input
                type="text"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                required
                className="w-full p-2 border rounded-lg focus:border-blue-500"
                placeholder="Enter OTP"
              />
            </div>

            <button
              type="submit"
              className="bg-blue-600 text-white w-full py-2 rounded-lg hover:bg-blue-700"
            >
              Verify OTP
            </button>
          </form>
        )}
      </div>
    </div>
  );
};

export default LoginPage;
